it("does not copy unsupported theme fields", () => {
  const theme = parseUserTheme("{accent: '#ffb86c', density: 'compact', previewLabel: 'ignored'}");

  assert.deepEqual(theme, {
    accent: "#ffb86c",
    density: "compact",
  });
  assert.equal(Object.hasOwn(theme, "previewLabel"), false);
});
